CREATE TABLE IF NOT EXISTS t_p97754588_arte_deli_site.orders (id SERIAL PRIMARY KEY, user_id INTEGER, status VARCHAR(30) DEFAULT 'processing', delivery_type VARCHAR(20) DEFAULT 'delivery', customer_name VARCHAR(100) NOT NULL, customer_phone VARCHAR(20) NOT NULL, address TEXT, apartment VARCHAR(20), entrance VARCHAR(10), floor VARCHAR(10), intercom VARCHAR(20), comment TEXT, delivery_time VARCHAR(50) DEFAULT 'asap', payment_method VARCHAR(30) DEFAULT 'cash', promo_code VARCHAR(50), discount INTEGER DEFAULT 0, subtotal INTEGER NOT NULL, delivery_cost INTEGER DEFAULT 0, total INTEGER NOT NULL, courier_id INTEGER, created_at TIMESTAMPTZ DEFAULT NOW(), updated_at TIMESTAMPTZ DEFAULT NOW())
